create_tables:
CREATE TABLE IF NOT EXISTS room_categories (category_id INTEGER PRIMARY KEY AUTOINCREMENT, category_name TEXT NOT NULL, base_price REAL NOT NULL);

CREATE TABLE IF NOT EXISTS rooms (room_id INTEGER PRIMARY KEY AUTOINCREMENT, room_number TEXT NOT NULL UNIQUE, category_id INTEGER REFERENCES room_categories(category_id), floor INTEGER NOT NULL, status TEXT DEFAULT 'available');

CREATE TABLE IF NOT EXISTS guests (guest_id INTEGER PRIMARY KEY AUTOINCREMENT, first_name TEXT NOT NULL, last_name TEXT NOT NULL, phone TEXT, email TEXT, total_spent REAL DEFAULT 0.0, registration_date DATE DEFAULT (DATE('now')));

CREATE TABLE IF NOT EXISTS stays (stay_id INTEGER PRIMARY KEY AUTOINCREMENT, guest_id INTEGER REFERENCES guests(guest_id), room_id INTEGER REFERENCES rooms(room_id), check_in_date DATE NOT NULL, check_out_date DATE NOT NULL, stay_status TEXT DEFAULT 'active', total_price REAL, payment_status TEXT DEFAULT 'paid', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);

CREATE TABLE IF NOT EXISTS staff (staff_id INTEGER PRIMARY KEY AUTOINCREMENT, first_name TEXT NOT NULL, last_name TEXT NOT NULL, position TEXT, phone TEXT, hire_date DATE);

CREATE TABLE IF NOT EXISTS services (service_id INTEGER PRIMARY KEY AUTOINCREMENT, service_name TEXT NOT NULL, price REAL NOT NULL);

CREATE TABLE IF NOT EXISTS room_tasks (task_id INTEGER PRIMARY KEY AUTOINCREMENT, room_id INTEGER REFERENCES rooms(room_id), staff_id INTEGER REFERENCES staff(staff_id), task_type TEXT NOT NULL, task_date DATE DEFAULT (DATE('now')), status TEXT DEFAULT 'pending');
